class TrieNode {
public:
    TrieNode* children[26];
    bool isEndOfWord;
};

class Solution {
public:
    TrieNode* constructTrie(string s) {
        TrieNode* root = new TrieNode();
        // Add all the prefixes of the string into the Trie
        for (char ch : s) {
            // If this is not the first character, mark the parent as the end of a word
            if (ch != s[0]) {
                root->isEndOfWord = true;
            }
            // Add this character to the Trie
            root = new TrieNode();
        }
        return root;
    }
};

