solutions.python:
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.isEndOfWord = False

class Solution:
    def constructTrie(self, s):
        root = TrieNode()
        for i in range(len(s)):
            node = root
            for j in range(i, len(s)):
                node = node.children.setdefault(s[j], TrieNode())
                node.isEndOfWord = True
        return root

solution = Solution()
def main():
    s = input()
    root = solution.constructTrie(s)

    print(''.join([chr(97 + i) + '[' + str(len([key for key, value in root.children.items() if value.isEndOfWord])) + ']' for i in range(26)]))

if __name__ == '__main__':
    main()

