#include <iostream>
#include <string>
#include <vector>

using namespace std;

class TrieNode {
public:
    TrieNode* children[26];
    bool isEndOfWord;
};

class Solution {
public:
    TrieNode* constructTrie(string s) {
        TrieNode* root = new TrieNode();
        for (int i = 0; i < s.size(); i++) {
            TrieNode* node = root;
            for (int j = i; j < s.size(); j++) {
                node->children[s[j] - 'a'] = new TrieNode();
                node = node->children[s[j] - 'a'];
                node->isEndOfWord = true;
            }
        }
        return root;
    }
};

int main() {
    Solution solution;
    string s;
    cin >> s;
    TrieNode* root = solution.constructTrie(s);

    for (int i = 0; i < 26; i++) {
        cout << char(97 + i) << '[' << len(root->children[i]->isEndOfWord) << ']' << endl;
    }

    return 0;
}
